mapper.select:
SELECT delegator_id
FROM approval_delegations
WHERE delegate_id = #{delegateId}
  AND active_marker IS NOT NULL
  AND starts_at <= #{now}
  AND ends_at >= #{now}

mapper.update:
UPDATE approval_delegations
SET active_marker = NULL, revoked_at = #{revokedAt}
WHERE delegator_id = #{delegatorId} AND active_marker IS NOT NULL

UPDATE approval_delegations
SET active_marker = NULL, revoked_at = #{now}
WHERE active_marker IS NOT NULL AND ends_at < #{now}
